      out.write("    menu_PUBLICO:[{l:'📋 Controlla appuntamento',id:'consultar_cita'},{l:'🏥 Servizi',id:'servicios'},{l:'🕐 Orari medici',id:'horarios'},{l:'📝 Come prenotare?',id:'como_sacar'},{l:'📞 Contatto',id:'contacto'}],\n");
      out.write("    menu_RECEPCIONISTA:[{l:'📋 Controlla appuntamento',id:'consultar_cita'},{l:'👥 Gestione pazienti',id:'guia_pacientes'},{l:'📅 Gestione appuntamenti',id:'guia_citas'},{l:'🏥 Servizi',id:'servicios'},{l:'📞 Contatto',id:'contacto'}],\n");
