      out.write("\n");
      out.write("/* ── Helpers ── */\n");
      out.write("function kEl(id){ return document.getElementById(id); }\n");
      out.write("function kT(key){\n");
      out.write("  var d = KIRA_T[KIRA.lang] || KIRA_T.es;\n");
      out.write("  return d[key] !== undefined ? d[key] : (KIRA_T.es[key] || '');\n");
      out.write("}\n");
      out.write("function kMenu(){\n");
      out.write("  var d = KIRA_T[KIRA.lang] || KIRA_T.es;\n");
      out.write("  return d['menu_'+KIRA.rol] || d.menu_PUBLICO || [];\n");
      out.write("}\n");
      out.write("function kBienvenida(){\n");
      out.write("  var txt = kT('bienvenida_'+KIRA.rol) || kT('bienvenida_PUBLICO');\n");
      out.write("  return txt.replace(/{n}/g, KIRA.nombre || '');\n");
      out.write("}\n");
      out.write("function kMd(t){\n");
      out.write("  return t.replace(/\\*\\*(.+?)\\*\\*/g,'<strong>$1</strong>')\n");
      out.write("          .replace(/\\*(.+?)\\*/g,'<em>$1</em>')\n");
      out.write("          .replace(/\\n/g,'<br>');\n");
      out.write("}\n");
      out.write("\n");
      out.write("var KIRA_ICON = '<svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M12 2C9.243 2 7 4.243 7 7s2.243 5 5 5 5-2.243 5-5-2.243-5-5-5zM12 10c-1.654 0-3-1.346-3-3s1.346-3 3-3 3 1.346 3 3-1.346 3-3 3zM21 21v-1c0-3.859-3.141-7-7-7h-4c-3.859 0-7 3.141-7 7v1h2v-1c0-2.757 2.243-5 5-5h4c2.757 0 5 2.243 5 5v1h2zM16 11h2v2h2v2h-2v2h-2v-2h-2v-2h2z\"/></svg>';\n");
      out.write("\n");
      out.write("function kAddMsg(txt, who){\n");
      out.write("  var msgs = kEl('kira-messages');\n");
      out.write("  var wrap = document.createElement('div');\n");
      out.write("  wrap.className = 'kira-msg kira-'+who;\n");
      out.write("  var av = document.createElement('div');\n");
      out.write("  av.className = 'kira-msg-av';\n");
      out.write("  if(who==='bot'){ av.innerHTML = KIRA_ICON; }\n");
      out.write("  else { av.textContent = KIRA.nombre ? KIRA.nombre.charAt(0).toUpperCase() : '?'; }\n");
      out.write("  var bub = document.createElement('div');\n");
      out.write("  bub.className = 'kira-bubble';\n");
      out.write("  bub.innerHTML = kMd(txt);\n");
      out.write("  wrap.appendChild(av); wrap.appendChild(bub);\n");
      out.write("  msgs.appendChild(wrap);\n");
      out.write("  msgs.scrollTop = msgs.scrollHeight;\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kShowTyping(){\n");
      out.write("  var msgs = kEl('kira-messages');\n");
      out.write("  var wrap = document.createElement('div');\n");
      out.write("  wrap.className = 'kira-msg kira-bot'; wrap.id = 'kira-ty';\n");
      out.write("  var av = document.createElement('div'); av.className='kira-msg-av'; av.innerHTML=KIRA_ICON;\n");
      out.write("  var dot = document.createElement('div'); dot.className='kira-typing';\n");
      out.write("  dot.innerHTML='<span></span><span></span><span></span>';\n");
      out.write("  wrap.appendChild(av); wrap.appendChild(dot);\n");
      out.write("  msgs.appendChild(wrap); msgs.scrollTop = msgs.scrollHeight;\n");
      out.write("}\n");
      out.write("function kHideTyping(){ var e=kEl('kira-ty'); if(e) e.remove(); }\n");
      out.write("\n");
      out.write("function kSetChips(items){\n");
      out.write("  var c = kEl('kira-chips'); c.innerHTML='';\n");
      out.write("  if(!items||!items.length) return;\n");
      out.write("  items.forEach(function(item){\n");
      out.write("    var btn = document.createElement('button');\n");
      out.write("    btn.className='kira-chip'; btn.textContent=item.l;\n");
      out.write("    btn.addEventListener('click', function(){ kHandle(item.id, item.l); });\n");
      out.write("    c.appendChild(btn);\n");
      out.write("  });\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kReply(txt, delay, chips){\n");
      out.write("  kShowTyping();\n");
      out.write("  setTimeout(function(){\n");
      out.write("    kHideTyping(); kAddMsg(txt,'bot'); kSetChips(chips||[]);\n");
      out.write("  }, delay||700);\n");
      out.write("}\n");
      out.write("\n");
      out.write("/* ── Flujos ── */\n");
      out.write("function kHandle(id, label){\n");
      out.write("  kAddMsg(label,'user'); kSetChips([]); KIRA.state='menu';\n");
      out.write("  var back = [{l:kT('volver'), id:'volver_menu'}];\n");
      out.write("  switch(id){\n");
      out.write("    case 'consultar_cita': kReply(kT('pedir_doc'),500); KIRA.state='esperando_doc'; break;\n");
      out.write("    case 'servicios':      kReply(kT('servicios'),600,back); break;\n");
      out.write("    case 'horarios':       kReply(kT('horarios'),600,back); break;\n");
      out.write("    case 'como_sacar':     kReply(kT('como_sacar'),600,back); break;\n");
      out.write("    case 'contacto':       kReply(kT('contacto'),600,back); break;\n");
      out.write("    case 'guia_pacientes': kReply(kT('guia_pacientes'),600,back); break;\n");
      out.write("    case 'guia_citas':     kReply(kT('guia_citas'),600,back); break;\n");
      out.write("    case 'estados_cita':   kReply(kT('estados_cita'),600,back); break;\n");
      out.write("    case 'citas_dia':      kReply(kT('citas_dia'),600,back); break;\n");
      out.write("    case 'volver_menu': case 'menu': kShowMenu(); break;\n");
      out.write("    default: kReply(kT('no_entiendo'),500,kMenu());\n");
      out.write("  }\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kShowMenu(){\n");
      out.write("  KIRA.state='menu';\n");
      out.write("  kShowTyping();\n");
      out.write("  setTimeout(function(){ kHideTyping(); kSetChips(kMenu()); }, 400);\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kSend(){\n");
      out.write("  var inp = kEl('kira-input');\n");
      out.write("  var txt = inp.value.trim();\n");
      out.write("  if(!txt) return;\n");
      out.write("  inp.value=''; inp.style.height='';\n");
      out.write("\n");
      out.write("  if(KIRA.state==='esperando_doc'){\n");
      out.write("    kAddMsg(txt,'user'); kSetChips([]);\n");
      out.write("    if(!/^\\d{5,15}$/.test(txt)){ kReply(kT('doc_invalido'),500); return; }\n");
      out.write("    KIRA.state='menu';\n");
      out.write("    kReply(kT('doc_ok').replace(/{d}/g,txt), 600, [{l:kT('volver'),id:'volver_menu'}]);\n");
      out.write("    return;\n");
      out.write("  }\n");
      out.write("\n");
      out.write("  kAddMsg(txt,'user');\n");
      out.write("  var lc = txt.toLowerCase();\n");
      out.write("  if(/cita|appointment|appuntamento|consultar|check|controlla/.test(lc))     kHandle('consultar_cita',txt);\n");
      out.write("  else if(/servicio|service|servizi/.test(lc))                               kHandle('servicios',txt);\n");
      out.write("  else if(/horario|schedule|orario/.test(lc))                                kHandle('horarios',txt);\n");
      out.write("  else if(/contact|contatto|contacto/.test(lc))                              kHandle('contacto',txt);\n");
      out.write("  else if(/como|how|come/.test(lc))                                          kHandle('como_sacar',txt);\n");
      out.write("  else if(/paciente|patient|paziente/.test(lc)&&KIRA.rol!=='PUBLICO')        kHandle('guia_pacientes',txt);\n");
      out.write("  else if(/estado|status|stato/.test(lc)&&KIRA.rol==='MEDICO')               kHandle('estados_cita',txt);\n");
      out.write("  else { kSetChips([]); kReply(kT('no_entiendo'),500,kMenu()); }\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kChangeLang(lang){\n");
      out.write("  KIRA.lang=lang;\n");
      out.write("  document.querySelectorAll('.kira-lang-pill').forEach(function(p){\n");
      out.write("    p.classList.toggle('kira-lang-active', p.getAttribute('data-lang')===lang);\n");
      out.write("  });\n");
      out.write("  kEl('kira-input').placeholder     = kT('placeholder');\n");
      out.write("  kEl('kira-status-txt').textContent = kT('status');\n");
      out.write("  kRestart(true);\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kToggle(){\n");
      out.write("  KIRA.open=!KIRA.open;\n");
      out.write("  kEl('kira-window').classList.toggle('kira-open', KIRA.open);\n");
      out.write("  kEl('kira-btn').classList.toggle('open', KIRA.open);\n");
      out.write("  if(KIRA.open){ kEl('kira-badge').style.display='none'; kEl('kira-input').focus(); }\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kRestart(silent){\n");
      out.write("  kEl('kira-messages').innerHTML=''; kEl('kira-chips').innerHTML='';\n");
